		termSq := term * term % MOD
		sumSq = (sumSq + termSq) % MOD
	}

	temp := (sumTerms * sumTerms) % MOD
	temp = (temp - sumSq + MOD) % MOD
	result := (temp * inv2) % MOD
	return result
}
